import type { SVGProps } from "react";

/**
 * Inline SVG icons for the console.
 *
 * Project convention: UI icons are SVGs, never emoji — they inherit the text
 * colour via `currentColor` and size via `1em`, so they theme cleanly. Add new
 * icons here rather than dropping in an emoji glyph.
 */

type IconProps = SVGProps<SVGSVGElement>;

function Svg({ children, ...props }: IconProps) {
  return (
    <svg
      width="1em"
      height="1em"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth={2}
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      focusable="false"
      {...props}
    >
      {children}
    </svg>
  );
}

